#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void solveCase(int X, int Y) {
    if ((X & 1) && (Y & 1)) { printf("-1\n"); return; }
    if (X == 0 || Y == 0) { printf("-1\n"); return; }
    if ((X & 1) && X == 1) { printf("-1\n"); return; }
    if ((Y & 1) && Y == 1) { printf("-1\n"); return; }
    int aHalf = X / 2;
    int bHalf = Y / 2;
    char centre = 0;
    if (X & 1) centre = 'a';
    else if (Y & 1) centre = 'b';
    int len = X + Y;
    char *first = (char*)malloc(aHalf + bHalf + 1);
    char *second = (char*)malloc(aHalf + bHalf + 1);
    int pos = 0;
    for (int i = 0; i < aHalf; ++i) first[pos++] = 'a';
    for (int i = 0; i < bHalf; ++i) first[pos++] = 'b';
    first[pos] = '\0';
    pos = 0;
    for (int i = 0; i < bHalf; ++i) second[pos++] = 'b';
    for (int i = 0; i < aHalf; ++i) second[pos++] = 'a';
    second[pos] = '\0';
    // build and print first palindrome
    for (int i = 0; i < aHalf + bHalf; ++i) putchar(first[i]);
    if (centre) putchar(centre);
    for (int i = aHalf + bHalf - 1; i >= 0; --i) putchar(first[i]);
    putchar('\n');
    // second palindrome
    for (int i = 0; i < aHalf + bHalf; ++i) putchar(second[i]);
    if (centre) putchar(centre);
    for (int i = aHalf + bHalf - 1; i >= 0; --i) putchar(second[i]);
    putchar('\n');
    free(first);
    free(second);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int X, Y; scanf("%d %d", &X, &Y);
        solveCase(X, Y);
    }
    return 0;
}

