    int aHalf = X / 2, bHalf = Y / 2;
    char centre = 0;
    if (X & 1) centre = 'a';
    else if (Y & 1) centre = 'b';
    string firstHalf(aHalf, 'a');
    firstHalf.append(bHalf, 'b');
    string secondHalf(bHalf, 'b');
    secondHalf.append(aHalf, 'a');
    auto build = [&](const string &fh) {
        string res = fh;
        if (centre) res.push_back(centre);
        res.append(string(fh.rbegin(), fh.rend()));
        return res;
    };
    cout << build(firstHalf) << '\n';
    cout << build(secondHalf) << '\n';
}

