import java.io.*;
import java.util.*;

public class Main {
    private static String build(String half, char centre) {
        StringBuilder sb = new StringBuilder();
        sb.append(half);
        if (centre != 0) sb.append(centre);
        sb.append(new StringBuilder(half).reverse());
        return sb.toString();
    }
    private static void solve(int X, int Y, StringBuilder out) {
        if ((X & 1) == 1 && (Y & 1) == 1) { out.append("-1\n"); return; }
        if (X == 0 || Y == 0) { out.append("-1\n"); return; }
        if ((X & 1) == 1 && X == 1) { out.append("-1\n"); return; }
        if ((Y & 1) == 1 && Y == 1) { out.append("-1\n"); return; }
        int aHalf = X / 2, bHalf = Y / 2;
        char centre = 0;
        if ((X & 1) == 1) centre = 'a';
        else if ((Y & 1) == 1) centre = 'b';
        StringBuilder firstHalf = new StringBuilder();
        for (int i = 0; i < aHalf; ++i) firstHalf.append('a');
        for (int i = 0; i < bHalf; ++i) firstHalf.append('b');
        StringBuilder secondHalf = new StringBuilder();
        for (int i = 0; i < bHalf; ++i) secondHalf.append('b');
        for (int i = 0; i < aHalf; ++i) secondHalf.append('a');
        out.append(build(firstHalf.toString(), centre)).append('\n');
        out.append(build(secondHalf.toString(), centre)).append('\n');
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; ++t) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int X = Integer.parseInt(st.nextToken());
            int Y = Integer.parseInt(st.nextToken());
            solve(X, Y, out);
        }
        System.out.print(out.toString());
    }
}

