#!/usr/bin/env python3
import sys

def solve_case(X, Y):
    if (X & 1) and (Y & 1):
        return ["-1"]
    if X == 0 or Y == 0:
        return ["-1"]
    if (X & 1) and X == 1:
        return ["-1"]
    if (Y & 1) and Y == 1:
        return ["-1"]
    a_half = X // 2
    b_half = Y // 2
    centre = ''
    if X & 1:
        centre = 'a'
    elif Y & 1:
        centre = 'b'
    first_half = 'a' * a_half + 'b' * b_half
    second_half = 'b' * b_half + 'a' * a_half
    def build(half):
        return half + centre + half[::-1]
    return [build(first_half), build(second_half)]

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        X = int(next(it)); Y = int(next(it))
        res = solve_case(X, Y)
        out_lines.extend(res)
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

